CREATE TABLE cybersecurity_tool_to_system
(
	id serial,
	cybersecurity_tool_id integer NOT NULL,
	system_id integer DEFAULT NULL,
	CONSTRAINT pk_cybersecurity_tool_to_technology PRIMARY KEY (id)
	, CONSTRAINT fk_cybersecurity_tool_to_system_to_cybersecurity_tool FOREIGN KEY (cybersecurity_tool_id) REFERENCES cybersecurity_tools (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_cybersecurity_tool_to_system_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_cybersecurity_tool_to_system_to_cybersecurity_tool ON cybersecurity_tool_to_system (cybersecurity_tool_id);
CREATE INDEX i_cybersecurity_tool_to_system_to_system ON cybersecurity_tool_to_system (system_id);
